2603	void Testbed::begin_vr_frame_and_handle_vr_input() {
2604		if (!m_hmd) {
2605			m_vr_frame_info = nullptr;
2606			return;
2607		}
2608	
2609		m_hmd->poll_events();
2610		if (!m_hmd->must_run_frame_loop()) {
2611			m_vr_frame_info = nullptr;
2612			return;
2613		}
2614	
2615		m_vr_frame_info = m_hmd->begin_frame();
2616	
2617		const auto& views = m_vr_frame_info->views;
2618		size_t n_views = views.size();
2619		size_t n_devices = m_devices.size();
2620		if (n_views > 0) {
2621			set_n_views(n_views);
2622	
2623			ivec2 total_size = 0;
2624			for (size_t i = 0; i < n_views; ++i) {
2625				ivec2 view_resolution = {views[i].view.subImage.imageRect.extent.width, views[i].view.subImage.imageRect.extent.height};
2626				total_size += view_resolution;
2627	
2628				m_views[i].full_resolution = view_resolution;
2629	
2630				// Apply the VR pose relative to the world camera transform.
2631				m_views[i].camera0 = mat3(m_camera) * views[i].pose;
2632				m_views[i].camera0[3] = vr_to_world(views[i].pose[3]);
2633				m_views[i].camera1 = m_views[i].camera0;
2634	
2635				m_views[i].visualized_dimension = m_visualized_dimension;
2636	
2637				const auto& xr_fov = views[i].view.fov;
2638	
2639				// Compute the distance on the image plane (1 unit away from the camera) that an angle of the respective FOV spans
2640				vec2 rel_focal_length_left_down = 0.5f *
2641					fov_to_focal_length(ivec2(1), vec2{360.0f * xr_fov.angleLeft / PI(), 360.0f * xr_fov.angleDown / PI()});
2642				vec2 rel_focal_length_right_up = 0.5f *
2643					fov_to_focal_length(ivec2(1), vec2{360.0f * xr_fov.angleRight / PI(), 360.0f * xr_fov.angleUp / PI()});
2644	
2645				// Compute total distance (for X and Y) that is spanned on the image plane.
2646				m_views[i].relative_focal_length = rel_focal_length_right_up - rel_focal_length_left_down;
2647	
2648				// Compute fraction of that distance that is spanned by the right-up part and set screen center accordingly.
2649				vec2 ratio = rel_focal_length_right_up / m_views[i].relative_focal_length;
2650				m_views[i].screen_center = {1.0f - ratio.x, ratio.y};
2651	
2652				// Fix up weirdness in the rendering pipeline
2653				m_views[i].relative_focal_length[(m_fov_axis + 1) % 2] *= (float)view_resolution[(m_fov_axis + 1) % 2] /
2654					(float)view_resolution[m_fov_axis];
2655				m_views[i].render_buffer->set_hidden_area_mask(m_vr_use_hidden_area_mask ? views[i].hidden_area_mask : nullptr);
2656	
2657				// Render each view on a different GPU (if available)
2658				m_views[i].device = m_use_aux_devices ? &m_devices.at(i % m_devices.size()) : &primary_device();
2659			}
2660	
2661			// Put all the views next to each other, but at half size
2662			glfwSetWindowSize(m_glfw_window, total_size.x / 2, (total_size.y / 2) / n_views);
2663	
2664			// VR controller input
2665			const auto& hands = m_vr_frame_info->hands;
2666			m_fps_camera = true;
2667	
2668			// TRANSLATE BY STICK (if not pressing the stick)
2669			if (!hands[0].pressing) {
2670				vec3 translate_vec = vec3{hands[0].thumbstick.x, 0.0f, hands[0].thumbstick.y} * m_camera_velocity * m_frame_ms.val() / 1000.0f;
2671				if (translate_vec != vec3(0.0f)) {
2672					translate_camera(translate_vec, mat3(m_views.front().camera0), false);
2673				}
2674			}
2675	
2676			// TURN BY STICK (if not pressing the stick)
2677			if (!hands[1].pressing) {
2678				auto prev_camera = m_camera;
2679	
2680				// Turn around the up vector (equivalent to x-axis mouse drag) with right joystick left/right
2681				float sensitivity = 0.35f;
2682				auto rot = rotation_from_angles({-2.0f * PI() * sensitivity * hands[1].thumbstick.x * m_frame_ms.val() / 1000.0f, 0.0f}) *
2683					mat3(m_camera);
2684				m_camera = mat4x3(rot[0], rot[1], rot[2], m_camera[3]);
2685	
2686				// Translate camera such that center of rotation was about the current view
2687				m_camera[3] += mat3(prev_camera) * views[0].pose[3] * m_scale - mat3(m_camera) * views[0].pose[3] * m_scale;
2688			}
2689	
2690			// TRANSLATE, SCALE, AND ROTATE BY GRAB
2691			{
2692				bool both_grabbing = hands[0].grabbing && hands[1].grabbing;
2693				float drag_factor = both_grabbing ? 0.5f : 1.0f;
2694	
2695				if (both_grabbing) {
2696					drag_factor = 0.5f;
2697	
2698					vec3 prev_diff = hands[0].prev_grab_pos - hands[1].prev_grab_pos;
2699					vec3 diff = hands[0].grab_pos - hands[1].grab_pos;
2700					vec3 center = 0.5f * (hands[0].grab_pos + hands[1].grab_pos);
2701	
2702					vec3 center_world = vr_to_world(0.5f * (hands[0].grab_pos + hands[1].grab_pos));
2703	
2704					// Scale around center position of the two dragging hands. Makes the scaling feel similar to phone pinch-to-zoom
2705					float scale = m_scale * length(prev_diff) / length(diff);
2706					m_camera[3] = (view_pos() - center_world) * (scale / m_scale) + center_world;
2707					m_scale = scale;
2708	
2709					// Take rotational component and project it to the nearest rotation about the up vector.
2710					// We don't want to rotate the scene about any other axis.
2711					vec3 rot = cross(normalize(prev_diff), normalize(diff));
2712					float rot_radians = std::asin(dot(m_up_dir, rot));
2713	
2714					auto prev_camera = m_camera;
2715					auto rotcam = rotmat(rot_radians, m_up_dir) * mat3(m_camera);
2716					m_camera = mat4x3(rotcam[0], rotcam[1], rotcam[2], m_camera[3]);
2717					m_camera[3] += mat3(prev_camera) * center * m_scale - mat3(m_camera) * center * m_scale;
2718				}
2719	
2720				for (const auto& hand : hands) {
2721					if (hand.grabbing) {
2722						m_camera[3] -= drag_factor * mat3(m_camera) * hand.drag() * m_scale;
2723					}
2724				}
2725			}
2726	
2727			// ERASE OCCUPANCY WHEN PRESSING STICK/TRACKPAD
2728			if (m_testbed_mode == ETestbedMode::Nerf) {
2729				for (const auto& hand : hands) {
2730					if (hand.pressing) {
2731						mark_density_grid_in_sphere_empty(vr_to_world(hand.pose[3]), m_scale * 0.05f, m_stream.get());
2732					}
2733				}
2734			}
2735		}
2736	}
