2766	void Testbed::init_opengl_shaders() {
2767		static const char* shader_vert = R"glsl(#version 140
2768			out vec2 UVs;
2769			void main() {
2770				UVs = vec2((gl_VertexID << 1) & 2, gl_VertexID & 2);
2771				gl_Position = vec4(UVs * 2.0 - 1.0, 0.0, 1.0);
2772			})glsl";
2773	
2774		static const char* shader_frag = R"glsl(#version 140
2775			in vec2 UVs;
2776			out vec4 frag_color;
2777			uniform sampler2D rgba_texture;
2778			uniform sampler2D depth_texture;
2779	
2780			struct FoveationWarp {
2781				float al, bl, cl;
2782				float am, bm;
2783				float ar, br, cr;
2784				float switch_left, switch_right;
2785				float inv_switch_left, inv_switch_right;
2786			};
2787	
2788			uniform FoveationWarp warp_x;
2789			uniform FoveationWarp warp_y;
2790	
2791			float unwarp(in FoveationWarp warp, float y) {
2792				y = clamp(y, 0.0, 1.0);
2793				if (y < warp.inv_switch_left) {
2794					return (sqrt(-4.0 * warp.al * warp.cl + 4.0 * warp.al * y + warp.bl * warp.bl) - warp.bl) / (2.0 * warp.al);
2795				} else if (y > warp.inv_switch_right) {
2796					return (sqrt(-4.0 * warp.ar * warp.cr + 4.0 * warp.ar * y + warp.br * warp.br) - warp.br) / (2.0 * warp.ar);
2797				} else {
2798					return (y - warp.bm) / warp.am;
2799				}
2800			}
2801	
2802			vec2 unwarp(in vec2 pos) {
2803				return vec2(unwarp(warp_x, pos.x), unwarp(warp_y, pos.y));
2804			}
2805	
2806			void main() {
2807				vec2 tex_coords = UVs;
2808				tex_coords.y = 1.0 - tex_coords.y;
2809				tex_coords = unwarp(tex_coords);
2810				frag_color = texture(rgba_texture, tex_coords.xy);
2811				//Uncomment the following line of code to visualize debug the depth buffer for debugging.
2812				// frag_color = vec4(vec3(texture(depth_texture, tex_coords.xy).r), 1.0);
2813				gl_FragDepth = texture(depth_texture, tex_coords.xy).r;
2814			})glsl";
2815	
2816		GLuint vert = glCreateShader(GL_VERTEX_SHADER);
2817		glShaderSource(vert, 1, &shader_vert, NULL);
2818		glCompileShader(vert);
2819		check_shader(vert, "Blit vertex shader", false);
2820	
2821		GLuint frag = glCreateShader(GL_FRAGMENT_SHADER);
2822		glShaderSource(frag, 1, &shader_frag, NULL);
2823		glCompileShader(frag);
2824		check_shader(frag, "Blit fragment shader", false);
2825	
2826		m_blit_program = glCreateProgram();
2827		glAttachShader(m_blit_program, vert);
2828		glAttachShader(m_blit_program, frag);
2829		glLinkProgram(m_blit_program);
2830		check_shader(m_blit_program, "Blit shader program", true);
2831	
2832		glDeleteShader(vert);
2833		glDeleteShader(frag);
2834	
2835		glGenVertexArrays(1, &m_blit_vao);
2836	}
