2838	void Testbed::blit_texture(
2839		const Foveation& foveation,
2840		GLint rgba_texture,
2841		GLint rgba_filter_mode,
2842		GLint depth_texture,
2843		GLint framebuffer,
2844		const ivec2& offset,
2845		const ivec2& resolution
2846	) {
2847		if (m_blit_program == 0) {
2848			return;
2849		}
2850	
2851		// Blit image to OpenXR swapchain.
2852		// Note that the OpenXR swapchain is 8bit while the rendering is in a float texture.
2853		// As some XR runtimes do not support float swapchains, we can't render into it directly.
2854	
2855		bool tex = glIsEnabled(GL_TEXTURE_2D);
2856		bool depth = glIsEnabled(GL_DEPTH_TEST);
2857		bool cull = glIsEnabled(GL_CULL_FACE);
2858	
2859		if (!tex) {
2860			glEnable(GL_TEXTURE_2D);
2861		}
2862		if (!depth) {
2863			glEnable(GL_DEPTH_TEST);
2864		}
2865		if (cull) {
2866			glDisable(GL_CULL_FACE);
2867		}
2868	
2869		glDepthFunc(GL_ALWAYS);
2870		glDepthMask(GL_TRUE);
2871	
2872		glBindVertexArray(m_blit_vao);
2873		glUseProgram(m_blit_program);
2874		glUniform1i(glGetUniformLocation(m_blit_program, "rgba_texture"), 0);
2875		glUniform1i(glGetUniformLocation(m_blit_program, "depth_texture"), 1);
2876	
2877		auto bind_warp = [&](const FoveationPiecewiseQuadratic& warp, const std::string& uniform_name) {
2878			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".al").c_str()), warp.al);
2879			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".bl").c_str()), warp.bl);
2880			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".cl").c_str()), warp.cl);
2881	
2882			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".am").c_str()), warp.am);
2883			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".bm").c_str()), warp.bm);
2884	
2885			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".ar").c_str()), warp.ar);
2886			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".br").c_str()), warp.br);
2887			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".cr").c_str()), warp.cr);
2888	
2889			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".switch_left").c_str()), warp.switch_left);
2890			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".switch_right").c_str()), warp.switch_right);
2891	
2892			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".inv_switch_left").c_str()), warp.inv_switch_left);
2893			glUniform1f(glGetUniformLocation(m_blit_program, (uniform_name + ".inv_switch_right").c_str()), warp.inv_switch_right);
2894		};
2895	
2896		bind_warp(foveation.warp_x, "warp_x");
2897		bind_warp(foveation.warp_y, "warp_y");
2898	
2899		glActiveTexture(GL_TEXTURE1);
2900		glBindTexture(GL_TEXTURE_2D, depth_texture);
2901		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S, GL_REPEAT);
2902		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T, GL_REPEAT);
2903		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_NEAREST);
2904		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_NEAREST);
2905	
2906		glActiveTexture(GL_TEXTURE0);
2907		glBindTexture(GL_TEXTURE_2D, rgba_texture);
2908		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S, GL_REPEAT);
2909		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T, GL_REPEAT);
2910		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, rgba_filter_mode);
2911		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, rgba_filter_mode);
2912	
2913		glBindFramebuffer(GL_FRAMEBUFFER, framebuffer);
2914		glViewport(offset.x, offset.y, resolution.x, resolution.y);
2915	
2916		glDrawArrays(GL_TRIANGLES, 0, 3);
2917	
2918		glBindVertexArray(0);
2919		glUseProgram(0);
2920	
2921		glDepthFunc(GL_LESS);
2922	
2923		// restore old state
2924		if (!tex) {
2925			glDisable(GL_TEXTURE_2D);
2926		}
2927		if (!depth) {
2928			glDisable(GL_DEPTH_TEST);
2929		}
2930		if (cull) {
2931			glEnable(GL_CULL_FACE);
2932		}
2933		glBindFramebuffer(GL_FRAMEBUFFER, 0);
2934	}
