4561	void Testbed::train(uint32_t batch_size) {
4562		if (!m_training_data_available || m_camera_path.rendering) {
4563			m_train = false;
4564			return;
4565		}
4566	
4567		if (m_testbed_mode == ETestbedMode::None) {
4568			throw std::runtime_error{"Cannot train without a mode."};
4569		}
4570	
4571		set_all_devices_dirty();
4572	
4573		// If we don't have a trainer, as can happen when having loaded training data or changed modes without having
4574		// explicitly loaded a new neural network.
4575		if (!m_trainer) {
4576			reload_network_from_file();
4577			if (!m_trainer) {
4578				throw std::runtime_error{"Unable to create a neural network trainer."};
4579			}
4580		}
4581	
4582		if (m_testbed_mode == ETestbedMode::Nerf) {
4583			if (m_nerf.training.optimize_extra_dims) {
4584				if (m_nerf.training.dataset.n_extra_learnable_dims == 0) {
4585					m_nerf.training.dataset.n_extra_learnable_dims = 16;
4586					reset_network();
4587				}
4588			}
4589		}
4590	
4591		if (!m_dlss) {
4592			// No immediate redraw necessary
4593			reset_accumulation(false, false);
4594		}
4595	
4596		uint32_t n_prep_to_skip = m_testbed_mode == ETestbedMode::Nerf ? clamp(m_training_step / 16u, 1u, 16u) : 1u;
4597		if (m_training_step % n_prep_to_skip == 0) {
4598			auto start = std::chrono::steady_clock::now();
4599			ScopeGuard timing_guard{[&]() {
4600				m_training_prep_ms.update(
4601					std::chrono::duration<float, std::milli>(std::chrono::steady_clock::now() - start).count() / n_prep_to_skip
4602				);
4603			}};
4604	
4605			switch (m_testbed_mode) {
4606				case ETestbedMode::Nerf: training_prep_nerf(batch_size, m_stream.get()); break;
4607				case ETestbedMode::Sdf: training_prep_sdf(batch_size, m_stream.get()); break;
4608				case ETestbedMode::Image: training_prep_image(batch_size, m_stream.get()); break;
4609				case ETestbedMode::Volume: training_prep_volume(batch_size, m_stream.get()); break;
4610				default: throw std::runtime_error{"Invalid training mode."};
4611			}
4612	
4613			CUDA_CHECK_THROW(cudaStreamSynchronize(m_stream.get()));
4614		}
4615	
4616		// Find leaf optimizer and update its settings
4617		json* leaf_optimizer_config = &m_network_config["optimizer"];
4618		while (leaf_optimizer_config->contains("nested")) {
4619			leaf_optimizer_config = &(*leaf_optimizer_config)["nested"];
4620		}
4621		(*leaf_optimizer_config)["optimize_matrix_params"] = m_train_network;
4622		(*leaf_optimizer_config)["optimize_non_matrix_params"] = m_train_encoding;
